@@ -0,0 +1,798 @@
+import Clutter from 'gi://Clutter';
+import Gio from 'gi://Gio';
+import GLib from 'gi://GLib';
+import Meta from 'gi://Meta';
+import Shell from 'gi://Shell';
+import * as Main from 'resource:///org/gnome/shell/ui/main.js';
+import {Extension} from 'resource:///org/gnome/shell/extensions/extension.js';
+
+import {MonitorGrid, cellsForWindow} from './lib/gridEngine.js';
+import {ScaleManager} from './lib/scaleManager.js';
+import {FocusRankList} from './lib/focusTracker.js';
+import {InPlacePlacer, ShelfPlacer, PackPlacer} from './lib/stampPlacer.js';
+import {DragHandler} from './lib/dragHandler.js';
+import {InputRouter} from './lib/inputRouter.js';
+import {WindowStateHandler} from './lib/windowStateHandler.js';
+import {
+    SCALE_STEPS, MIN_SCALE, scaleStepUp, scaleStepDown,
+    sanitizeConnector, BATCH_SHRINK_LIMIT,
+} from './lib/constants.js';
+
+export default class MutterButterExtension extends Extension {
+    enable() {
+        this._settings = this.getSettings();
+
+        // Per-monitor grids: monitorIndex -> MonitorGrid
+        this._grids = new Map();
+
+        // Cached placer instance (persists shelf state across calls)
+        this._cachedPlacer = null;
+        this._cachedPlacerMode = '';
+
+        // Track which windows have per-window signals connected
+        this._connectedWindows = new Set();
+
+        // Window ID -> MetaWindow lookup cache (avoids O(n) scans)
+        this._windowById = new Map();
+
+        // Modules
+        this._scaleManager = new ScaleManager();
+        this._focusRanks = new FocusRankList();
+        this._inputRouter = new InputRouter(
+            global.window_group, global.display);
+        this._dragHandler = new DragHandler({
+            display: global.display,
+            windowGroup: global.window_group,
+            topWindowGroup: global.top_window_group,
+            getGridForMonitor: (i) => this._grids.get(i),
+            getMonitorGeometry: (i) => global.display.get_monitor_geometry(i),
+            getMonitorCount: () => global.display.get_n_monitors(),
+            getWindowScaleState: (w) => this._scaleManager.getState(w),
+            onDropFullSize: (w, m, c, r) => this._onDropFullSize(w, m, c, r),
+            onDropStamp: (w, m, c, r) => this._onDropStamp(w, m, c, r),
+            inputRouter: this._inputRouter,
+        });
+
+        // Overview state
+        this._overviewActive = false;
+        this._queuedFocusEvents = [];
+
+        // Signal connections
+        this._signals = [];
+
+        // Initialize grids
+        this._initGrids();
+
+        // Focus tracking
+        this._connectSignal(global.display, 'notify::focus-window',
+            () => this._onFocusChanged());
+
+        // Window lifecycle
+        this._connectSignal(global.display, 'window-created',
+            (_display, metaWindow) => this._onWindowCreated(metaWindow));
+
+        // Monitor hotplug
+        this._connectSignal(Main.layoutManager, 'monitors-changed',
+            () => this._onMonitorsChanged());
+
+        // Cross-monitor moves
+        this._connectSignal(global.display, 'window-entered-monitor',
+            (_display, monitorIndex, metaWindow) =>
+                this._onWindowEnteredMonitor(metaWindow, monitorIndex));
+
+        // Overview
+        this._connectSignal(Main.overview, 'showing', () => this._onOverviewShowing());
+        this._connectSignal(Main.overview, 'hidden', () => this._onOverviewHidden());
+
+        // Keybindings
+        Main.wm.addKeybinding('zoom-in-keybind', this._settings,
+            Meta.KeyBindingFlags.NONE, Shell.ActionMode.NORMAL,
+            () => this._onZoomIn());
+        Main.wm.addKeybinding('zoom-out-keybind', this._settings,
+            Meta.KeyBindingFlags.NONE, Shell.ActionMode.NORMAL,
+            () => this._onZoomOut());
+
+        // Write monitor connectors for prefs.js
+        this._updateMonitorConnectors();
+
+        // Process existing windows
+        this._processExistingWindows();
+    }
+
+    disable() {
+        // Keybindings
+        Main.wm.removeKeybinding('zoom-in-keybind');
+        Main.wm.removeKeybinding('zoom-out-keybind');
+
+        // Signals
+        for (const {obj, id} of this._signals)
+            obj.disconnect(id);
+        this._signals = [];
+
+        // Drag
+        this._dragHandler.destroy();
+        this._dragHandler = null;
+
+        // Clones and state
+        this._scaleManager.destroyAll();
+        this._scaleManager = null;
+
+        // Input router (stamp layer)
+        this._inputRouter.destroy();
+        this._inputRouter = null;
+
+        // Grids and tracking state
+        this._grids.clear();
+        this._connectedWindows.clear();
+        this._windowById.clear();
+        this._focusRanks = null;
+        this._cachedPlacer = null;
+        this._settings = null;
+    }
+
+    // --- Signal helpers ---
+
+    _connectSignal(obj, signal, handler) {
+        const id = obj.connect(signal, handler);
+        this._signals.push({obj, id});
+    }
+
+    // --- Grid initialization ---
+
+    _initGrids() {
+        this._grids.clear();
+        const n = global.display.get_n_monitors();
+        for (let i = 0; i < n; i++) {
+            const workarea = global.display.get_monitor_workarea(i);
+            const connector = global.display.get_monitor_connector(i);
+            const sanitized = sanitizeConnector(connector || `monitor-${i}`);
+
+            // Read per-monitor settings via relocatable schema
+            const path = `/org/gnome/shell/extensions/mutter-butter/monitor/${sanitized}/`;
+            const monSettings = new Gio.Settings({
+                schema_id: 'org.gnome.shell.extensions.mutter-butter.monitor',
+                path,
+            });
+            const cols = monSettings.get_int('grid-columns');
+            const rows = monSettings.get_int('grid-rows');
+
+            this._grids.set(i, new MonitorGrid(workarea.width, workarea.height, cols, rows));
+        }
+    }
+
+    _updateMonitorConnectors() {
+        const connectors = [];
+        const n = global.display.get_n_monitors();
+        for (let i = 0; i < n; i++) {
+            const c = global.display.get_monitor_connector(i);
+            if (c) connectors.push(c);
+        }
+        this._settings.set_strv('monitor-connectors', connectors);
+    }
+
+    // --- Focus handling ---
+
+    _onFocusChanged() {
+        const metaWindow = global.display.focus_window;
+        if (!metaWindow)
+            return;
+        if (!WindowStateHandler.isManaged(metaWindow))
+            return;
+        if (this._overviewActive) {
+            this._queuedFocusEvents.push(metaWindow);
+            return;
+        }
+        this._handleFocus(metaWindow);
+    }
+
+    _handleFocus(metaWindow, isDirect = true) {
+        const state = this._scaleManager.getState(metaWindow);
+
+        // If unplaced, ignore (will be handled on first-frame)
+        const windowId = this._windowId(metaWindow);
+        if (this._focusRanks.getRank(windowId) === -1)
+            return;
+
+        this._focusRanks.onFocus(windowId);
+
+        // Auto-restore if auto-shrunk
+        if (state && state.scaleSource === 'auto' && state.scaleFactor < 1.0 - 0.001) {
+            const hysteresisMs = this._settings.get_int('hysteresis-ms');
+            // Direct user actions (clicking a stamp) bypass hysteresis.
+            // Indirect triggers (chain reactions) respect it.
+            if (isDirect || !this._scaleManager.isRecentlyShrunk(metaWindow, hysteresisMs)) {
+                this._restoreWindow(metaWindow);
+            }
+        }
+
+        // Check if any windows need to be bumped (one bump max)
+        this._evaluateAutoShrink();
+    }
+
+    _restoreWindow(metaWindow) {
+        const restoreScale = this._scaleManager.autoRestore(metaWindow);
+        const state = this._scaleManager.getState(metaWindow);
+        const windowId = this._windowId(metaWindow);
+
+        // Remove stamp from grid
+        const monitorIndex = metaWindow.get_monitor();
+        const grid = this._grids.get(monitorIndex);
+        if (grid)
+            grid.removeWindow(windowId);
+
+        // Destroy clone (also removes container from its parent)
+        this._scaleManager.destroyClone(metaWindow);
+
+        if (restoreScale >= 1.0 - 0.001) {
+            // Full size — place in grid at previous cell or best-fit
+            if (grid) {
+                const prev = state.previousCellAllocation;
+                const frameRect = metaWindow.get_frame_rect();
+                const span = cellsForWindow(
+                    frameRect.width, frameRect.height,
+                    grid.cellWidth, grid.cellHeight, 1.0);
+                let placed = false;
+                if (prev && grid.isAreaFree(prev.col, prev.row, span.cols, span.rows)) {
+                    placed = grid.placeWindowAt(windowId, prev.col, prev.row, span.cols, span.rows);
+                }
+                let allocation = placed
+                    ? {col: prev.col, row: prev.row, spanCols: span.cols, spanRows: span.rows}
+                    : null;
+                if (!placed) {
+                    const pos = grid.placeWindow(windowId, span.cols, span.rows);
+                    if (pos)
+                        allocation = {col: pos.col, row: pos.row, spanCols: span.cols, spanRows: span.rows};
+                }
+                // Move window to its grid cell position
+                if (allocation) {
+                    const rect = grid.cellToPixels(allocation.col, allocation.row,
+                        allocation.spanCols, allocation.spanRows);
+                    const geo = global.display.get_monitor_geometry(monitorIndex);
+                    metaWindow.move_resize_frame(true,
+                        geo.x + rect.x, geo.y + rect.y, rect.width, rect.height);
+                }
+            }
+        } else {
+            // Partial restore — re-create clone at restored scale
+            this._createAndPlaceClone(metaWindow, restoreScale);
+        }
+    }
+
+    _evaluateAutoShrink() {
+        const threshold = this._settings.get_int('focus-rank-threshold');
+        const exemptApps = this._settings.get_strv('exempt-apps');
+        const hysteresisMs = this._settings.get_int('hysteresis-ms');
+
+        // Find windows that should be shrunk
+        const below = this._focusRanks.windowsBelowRank(threshold);
+        let bumped = false;
+
+        for (const windowId of below) {
+            if (bumped)
+                break; // One bump per focus event
+
+            const metaWindow = this._windowForId(windowId);
+            if (!metaWindow)
+                continue;
+
+            const state = this._scaleManager.getState(metaWindow);
+            if (state && state.scaleFactor < 1.0 - 0.001)
+                continue; // Already shrunk
+
+            if (WindowStateHandler.isImplicitlyExempt(metaWindow))
+                continue;
+
+            if (!this._scaleManager.canBump(metaWindow, exemptApps))
+                continue;
+
+            this._shrinkWindow(metaWindow);
+            bumped = true;
+        }
+    }
+
+    _shrinkWindow(metaWindow) {
+        const windowId = this._windowId(metaWindow);
+        const monitorIndex = metaWindow.get_monitor();
+        const grid = this._grids.get(monitorIndex);
+        const currentAlloc = grid ? grid.getWindow(windowId) : null;
+
+        this._scaleManager.autoShrink(metaWindow, currentAlloc);
+
+        // Remove from grid at current size
+        if (grid)
+            grid.removeWindow(windowId);
+
+        // Create clone and place stamp
+        this._createAndPlaceClone(metaWindow, MIN_SCALE);
+    }
+
+    _createAndPlaceClone(metaWindow, scaleFactor) {
+        const result = this._scaleManager.createClone(metaWindow, scaleFactor);
+        if (!result)
+            return;
+
+        const windowId = this._windowId(metaWindow);
+        const monitorIndex = metaWindow.get_monitor();
+        const grid = this._grids.get(monitorIndex);
+        if (!grid)
+            return;
+
+        const frameRect = metaWindow.get_frame_rect();
+        const span = cellsForWindow(
+            frameRect.width, frameRect.height,
+            grid.cellWidth, grid.cellHeight, scaleFactor);
+
+        // Get placer based on settings
+        const placer = this._getPlacer();
+        const currentAlloc = grid.getWindow(windowId);
+        const originalPos = currentAlloc
+            ? {col: currentAlloc.col, row: currentAlloc.row}
+            : null;
+
+        // Remove old allocation if any
+        grid.removeWindow(windowId);
+
+        const pos = placer.placeStamp(grid, windowId, span.cols, span.rows, originalPos);
+        if (pos) {
+            const rect = grid.cellToPixels(pos.col, pos.row, span.cols, span.rows);
+            const geo = global.display.get_monitor_geometry(monitorIndex);
+            this._inputRouter.addContainer(result.container, geo.x + rect.x, geo.y + rect.y);
+        }
+
+        // Wire click-to-activate AND drag initiation on container.
+        // Click activates (focusTracker handles restore).
+        // Press+move beyond threshold initiates stamp drag.
+        let pressX = 0, pressY = 0;
+        let pressHandlerId = 0, motionCheckId = 0;
+        const DRAG_THRESHOLD = 8; // pixels
+
+        pressHandlerId = result.container.connect('button-press-event', (_actor, event) => {
+            if (event.get_button() !== Clutter.BUTTON_PRIMARY)
+                return Clutter.EVENT_PROPAGATE;
+            [pressX, pressY] = event.get_coords();
+
+            // Connect a motion handler to detect drag threshold
+            motionCheckId = result.container.connect('motion-event', (_a, motionEvent) => {
+                const [mx, my] = motionEvent.get_coords();
+                if (Math.abs(mx - pressX) > DRAG_THRESHOLD ||
+                    Math.abs(my - pressY) > DRAG_THRESHOLD) {
+                    // Drag threshold exceeded — start stamp drag
+                    result.container.disconnect(motionCheckId);
+                    motionCheckId = 0;
+                    this._dragHandler.startStampDrag(metaWindow, result.container);
+                }
+                return Clutter.EVENT_STOP;
+            });
+            return Clutter.EVENT_STOP;
+        });
+
+        result.container.connect('button-release-event', (_actor, event) => {
+            if (motionCheckId) {
+                // Motion threshold never exceeded — this is a click, not a drag
+                result.container.disconnect(motionCheckId);
+                motionCheckId = 0;
+                metaWindow.activate(global.get_current_time());
+            }
+            return Clutter.EVENT_STOP;
+        });
+    }
+
+    _getPlacer() {
+        const mode = this._settings.get_string('placement-mode');
+        // Return cached instance if mode hasn't changed
+        if (this._cachedPlacer && this._cachedPlacerMode === mode)
+            return this._cachedPlacer;
+
+        switch (mode) {
+        case 'shelf': {
+            const edge = this._settings.get_string('shelf-edge');
+            const maxDepth = this._settings.get_int('shelf-max-depth');
+            this._cachedPlacer = new ShelfPlacer(edge, maxDepth);
+            break;
+        }
+        case 'pack':
+            this._cachedPlacer = new PackPlacer();
+            break;
+        default:
+            this._cachedPlacer = new InPlacePlacer();
+            break;
+        }
+        this._cachedPlacerMode = mode;
+        return this._cachedPlacer;
+    }
+
+    // --- Window lifecycle ---
+
+    _onWindowCreated(metaWindow) {
+        if (!WindowStateHandler.isManaged(metaWindow))
+            return;
+
+        // Wait for actor to be available, then for first-frame.
+        // Use timeout (not idle) to avoid spin-looping if actor is delayed.
+        let retries = 0;
+        const maxRetries = 20;
+        const checkActor = () => {
+            const actor = metaWindow.get_compositor_private();
+            if (actor) {
+                actor.connect('first-frame', () => {
+                    this._onWindowReady(metaWindow);
+                });
+                return GLib.SOURCE_REMOVE;
+            }
+            retries++;
+            if (retries >= maxRetries)
+                return GLib.SOURCE_REMOVE; // Give up
+            return GLib.SOURCE_CONTINUE;
+        };
+
+        // Try immediately, then poll with timeout
+        if (checkActor() === GLib.SOURCE_CONTINUE)
+            GLib.timeout_add(GLib.PRIORITY_DEFAULT, 50, checkActor);
+    }
+
+    _onWindowReady(metaWindow) {
+        if (WindowStateHandler.isFullscreen(metaWindow))
+            return;
+        if (WindowStateHandler.isMinimized(metaWindow))
+            return;
+
+        const windowId = this._windowId(metaWindow);
+        this._focusRanks.onFocus(windowId);
+
+        const monitorIndex = metaWindow.get_monitor();
+        const grid = this._grids.get(monitorIndex);
+        if (!grid)
+            return;
+
+        const frameRect = metaWindow.get_frame_rect();
+        const span = cellsForWindow(
+            frameRect.width, frameRect.height,
+            grid.cellWidth, grid.cellHeight, 1.0);
+
+        let pos = grid.placeWindow(windowId, span.cols, span.rows);
+        if (!pos) {
+            // Need to shrink windows to make room
+            this._batchShrinkForSpace(grid, monitorIndex, span.cols, span.rows);
+            pos = grid.placeWindow(windowId, span.cols, span.rows);
+        }
+
+        if (pos) {
+            const rect = grid.cellToPixels(pos.col, pos.row, span.cols, span.rows);
+            const geo = global.display.get_monitor_geometry(monitorIndex);
+            metaWindow.move_resize_frame(true,
+                geo.x + rect.x, geo.y + rect.y, rect.width, rect.height);
+        }
+
+        // Connect per-window signals
+        this._connectWindowSignals(metaWindow);
+
+        // Evaluate if this window push caused anyone to need shrinking
+        this._evaluateAutoShrink();
+    }
+
+    _batchShrinkForSpace(grid, monitorIndex, neededCols, neededRows) {
+        const exemptApps = this._settings.get_strv('exempt-apps');
+        let shrunk = 0;
+
+        // Try shrinking lowest-ranked windows until space is available
+        const ranks = this._focusRanks.getRanks();
+        for (let i = ranks.length - 1; i >= 0 && shrunk < BATCH_SHRINK_LIMIT; i--) {
+            const windowId = ranks[i];
+            const metaWindow = this._windowForId(windowId);
+            if (!metaWindow || metaWindow.get_monitor() !== monitorIndex)
+                continue;
+            if (WindowStateHandler.isImplicitlyExempt(metaWindow))
+                continue;
+            if (!this._scaleManager.canBump(metaWindow, exemptApps))
+                continue;
+
+            const state = this._scaleManager.getState(metaWindow);
+            if (state && state.scaleFactor < 1.0 - 0.001)
+                continue;
+
+            this._shrinkWindow(metaWindow);
+            shrunk++;
+
+            // Check if we have enough space now
+            const probeId = `__probe_${windowId}_${shrunk}`;
+            if (grid.placeWindow(probeId, neededCols, neededRows)) {
+                grid.removeWindow(probeId);
+                break;
+            }
+        }
+    }
+
+    _connectWindowSignals(metaWindow) {
+        // Guard against double-connection (e.g., on monitors-changed re-process)
+        if (this._connectedWindows.has(metaWindow))
+            return;
+        this._connectedWindows.add(metaWindow);
+
+        this._connectSignal(metaWindow, 'unmanaging', () => {
+            this._connectedWindows.delete(metaWindow);
+            this._onWindowUnmanaging(metaWindow);
+        });
+
+        this._connectSignal(metaWindow, 'notify::minimized', () => {
+            this._onMinimizedChanged(metaWindow);
+        });
+    }
+
+    _onWindowUnmanaging(metaWindow) {
+        const windowId = this._windowId(metaWindow);
+
+        // Cancel any active drag
+        if (this._dragHandler.dragWindow === metaWindow)
+            this._dragHandler.cancelDrag();
+
+        // Remove from grid
+        for (const grid of this._grids.values())
+            grid.removeWindow(windowId);
+
+        // Clean up state
+        this._scaleManager.removeState(metaWindow);
+        this._focusRanks.remove(windowId);
+        this._windowById.delete(windowId);
+
+        // Re-evaluate: maybe some auto-shrunk windows can be restored
+        this._onWindowClosedRestore();
+    }
+
+    _onWindowClosedRestore() {
+        const threshold = this._settings.get_int('focus-rank-threshold');
+        const ranks = this._focusRanks.getRanks();
+
+        // Count full-size eligible windows
+        let fullSizeCount = 0;
+        for (const windowId of ranks) {
+            const metaWindow = this._windowForId(windowId);
+            if (!metaWindow)
+                continue;
+            const state = this._scaleManager.getState(metaWindow);
+            if (!state || state.scaleFactor >= 1.0 - 0.001)
+                fullSizeCount++;
+        }
+
+        // Restore auto-shrunk windows in rank order until threshold is met
+        if (fullSizeCount < threshold) {
+            for (const windowId of ranks) {
+                if (fullSizeCount >= threshold)
+                    break;
+                const metaWindow = this._windowForId(windowId);
+                if (!metaWindow)
+                    continue;
+                const state = this._scaleManager.getState(metaWindow);
+                if (state && state.scaleSource === 'auto' && state.scaleFactor < 1.0 - 0.001) {
+                    this._restoreWindow(metaWindow);
+                    fullSizeCount++;
+                }
+            }
+        }
+    }
+
+    _onMinimizedChanged(metaWindow) {
+        const windowId = this._windowId(metaWindow);
+        if (metaWindow.minimized) {
+            // Remove from grid, destroy clone
+            for (const grid of this._grids.values())
+                grid.removeWindow(windowId);
+            const state = this._scaleManager.getState(metaWindow);
+            if (state && state.container) {
+                this._inputRouter.removeContainer(state.container);
+                this._scaleManager.destroyClone(metaWindow);
+            }
+        } else {
+            // Unminimized — re-place in grid
+            this._onWindowReady(metaWindow);
+        }
+    }
+
+    // --- Monitor changes ---
+
+    _onMonitorsChanged() {
+        this._initGrids();
+        this._updateMonitorConnectors();
+        this._processExistingWindows();
+    }
+
+    _onWindowEnteredMonitor(metaWindow, monitorIndex) {
+        if (!WindowStateHandler.isManaged(metaWindow))
+            return;
+        const windowId = this._windowId(metaWindow);
+        // Remove from all grids
+        for (const grid of this._grids.values())
+            grid.removeWindow(windowId);
+        // Re-place in target monitor grid
+        const grid = this._grids.get(monitorIndex);
+        if (!grid)
+            return;
+        const state = this._scaleManager.getState(metaWindow);
+        const scale = state ? state.scaleFactor : 1.0;
+        const frameRect = metaWindow.get_frame_rect();
+        const span = cellsForWindow(
+            frameRect.width, frameRect.height,
+            grid.cellWidth, grid.cellHeight, scale);
+        grid.placeWindow(windowId, span.cols, span.rows);
+    }
+
+    // --- Overview ---
+
+    _onOverviewShowing() {
+        if (this._overviewActive)
+            return;
+        this._overviewActive = true;
+        this._scaleManager.suspendAll();
+        this._inputRouter.suspend();
+    }
+
+    _onOverviewHidden() {
+        if (!this._overviewActive)
+            return;
+        this._overviewActive = false;
+        this._scaleManager.restoreAll();
+        this._inputRouter.restore();
+
+        // Process queued focus events
+        for (const metaWindow of this._queuedFocusEvents)
+            this._handleFocus(metaWindow);
+        this._queuedFocusEvents = [];
+    }
+
+    // --- Zoom keybindings ---
+
+    _onZoomIn() {
+        const metaWindow = global.display.focus_window;
+        if (!metaWindow)
+            return;
+        const state = this._scaleManager.getOrCreateState(metaWindow);
+        const newScale = scaleStepUp(state.scaleFactor);
+        if (Math.abs(newScale - state.scaleFactor) < 0.001)
+            return;
+
+        if (WindowStateHandler.isMaximized(metaWindow) || WindowStateHandler.isTiled(metaWindow))
+            WindowStateHandler.unmaximizeForScale(metaWindow);
+
+        this._scaleManager.manualScale(metaWindow, newScale);
+        this._updateWindowScale(metaWindow, newScale);
+    }
+
+    _onZoomOut() {
+        const metaWindow = global.display.focus_window;
+        if (!metaWindow)
+            return;
+        const state = this._scaleManager.getOrCreateState(metaWindow);
+        const newScale = scaleStepDown(state.scaleFactor);
+        if (Math.abs(newScale - state.scaleFactor) < 0.001)
+            return;
+
+        if (WindowStateHandler.isMaximized(metaWindow) || WindowStateHandler.isTiled(metaWindow))
+            WindowStateHandler.unmaximizeForScale(metaWindow);
+
+        this._scaleManager.manualScale(metaWindow, newScale);
+        this._updateWindowScale(metaWindow, newScale);
+    }
+
+    _updateWindowScale(metaWindow, newScale) {
+        const windowId = this._windowId(metaWindow);
+        const monitorIndex = metaWindow.get_monitor();
+        const grid = this._grids.get(monitorIndex);
+
+        // Remove from grid
+        if (grid)
+            grid.removeWindow(windowId);
+
+        // Destroy old clone (also removes container from parent)
+        this._scaleManager.destroyClone(metaWindow);
+
+        if (newScale >= 1.0 - 0.001) {
+            // Restore to full size — no clone needed
+            if (grid) {
+                const frameRect = metaWindow.get_frame_rect();
+                const span = cellsForWindow(
+                    frameRect.width, frameRect.height,
+                    grid.cellWidth, grid.cellHeight, 1.0);
+                grid.placeWindow(windowId, span.cols, span.rows);
+            }
+        } else {
+            // Scale down — create new clone
+            this._createAndPlaceClone(metaWindow, newScale);
+        }
+    }
+
+    // --- Drop handlers ---
+
+    _onDropFullSize(metaWindow, monitorIndex, col, row) {
+        const windowId = this._windowId(metaWindow);
+        // Remove from old position
+        for (const grid of this._grids.values())
+            grid.removeWindow(windowId);
+
+        const grid = this._grids.get(monitorIndex);
+        if (!grid)
+            return;
+
+        const frameRect = metaWindow.get_frame_rect();
+        const span = cellsForWindow(
+            frameRect.width, frameRect.height,
+            grid.cellWidth, grid.cellHeight, 1.0);
+
+        const clampedCol = Math.min(col, grid.cols - span.cols);
+        const clampedRow = Math.min(row, grid.rows - span.rows);
+
+        let placed = grid.placeWindowAt(windowId, clampedCol, clampedRow, span.cols, span.rows);
+        if (!placed) {
+            // Target occupied — fall back to best-fit
+            const pos = grid.placeWindow(windowId, span.cols, span.rows);
+            if (!pos) return;
+            placed = true;
+            Object.assign(span, {col: pos.col, row: pos.row});
+        }
+        const finalCol = placed ? clampedCol : span.col;
+        const finalRow = placed ? clampedRow : span.row;
+        const rect = grid.cellToPixels(clampedCol, clampedRow, span.cols, span.rows);
+        const geo = global.display.get_monitor_geometry(monitorIndex);
+        metaWindow.move_resize_frame(true,
+            geo.x + rect.x, geo.y + rect.y, rect.width, rect.height);
+    }
+
+    _onDropStamp(metaWindow, monitorIndex, col, row) {
+        const windowId = this._windowId(metaWindow);
+        const state = this._scaleManager.getState(metaWindow);
+        if (!state)
+            return;
+
+        for (const grid of this._grids.values())
+            grid.removeWindow(windowId);
+
+        const grid = this._grids.get(monitorIndex);
+        if (!grid)
+            return;
+
+        const frameRect = metaWindow.get_frame_rect();
+        const span = cellsForWindow(
+            frameRect.width, frameRect.height,
+            grid.cellWidth, grid.cellHeight, state.scaleFactor);
+
+        const clampedCol = Math.min(col, grid.cols - span.cols);
+        const clampedRow = Math.min(row, grid.rows - span.rows);
+
+        grid.placeWindowAt(windowId, clampedCol, clampedRow, span.cols, span.rows);
+        const rect = grid.cellToPixels(clampedCol, clampedRow, span.cols, span.rows);
+        const geo = global.display.get_monitor_geometry(monitorIndex);
+
+        // Move the real window to the new grid position. Keep its original
+        // (unscaled) dimensions — the clone handles the visual scaling.
+        // (reuse frameRect from earlier in this function)
+        this._scaleManager.setDragFinalizing(true);
+        metaWindow.move_resize_frame(true,
+            geo.x + rect.x, geo.y + rect.y,
+            frameRect.width, frameRect.height);
+        this._scaleManager.setDragFinalizing(false);
+
+        if (state.container) {
+            this._inputRouter.moveContainer(state.container, geo.x + rect.x, geo.y + rect.y);
+        }
+    }
+
+    // --- Utilities ---
+
+    _processExistingWindows() {
+        const windows = global.get_window_actors()
+            .map(a => a.meta_window)
+            .filter(w => w && WindowStateHandler.isManaged(w));
+
+        for (const metaWindow of windows)
+            this._onWindowReady(metaWindow);
+    }
+
+    _windowId(metaWindow) {
+        const id = `${metaWindow.get_stable_sequence()}`;
+        this._windowById.set(id, metaWindow);
+        return id;
+    }
+
+    _windowForId(windowId) {
+        const w = this._windowById.get(windowId);
+        return (w && !w.is_unmanaging?.()) ? w : null;
+    }
+}
